import { useState, useEffect } from 'react';
import { X } from 'lucide-react';
import type { WidgetConfig } from '../../types';
import { sendBindingValue } from './binding';
import { useAppStore } from '../../store/appStore';
import clsx from 'clsx';

interface ButtonWidgetProps {
  widget: Extract<WidgetConfig, { kind: 'Button' }>;
  onRemove: () => void;
}

/// 按钮控件 — 按下发送 press_value, 释放发送 release_value
/// 当前值通过 setInputValue 推送到后端图 (事件驱动, 供下游 widget 读取)
export function ButtonWidget({ widget, onRemove }: ButtonWidgetProps) {
  const { label, press_value, release_value, binding, id } = widget.params;
  const [pressed, setPressed] = useState(false);
  const setInputValue = useAppStore((s) => s.setInputValue);
  const value = pressed ? press_value : release_value;

  const handleDown = () => {
    setPressed(true);
    sendBindingValue(binding, press_value);
  };
  const handleUp = () => {
    setPressed(false);
    sendBindingValue(binding, release_value);
  };

  // 同步当前值到后端图 (事件驱动)
  useEffect(() => {
    setInputValue(id, value);
  }, [id, value, setInputValue]);

  return (
    <div className="group bg-bg-sidebar border border-border rounded p-2.5 min-w-[140px] flex flex-col gap-1.5 relative">
      <button
        className="absolute top-1 right-1 opacity-0 transition-opacity duration-150 group-hover:opacity-100 w-6 h-6 flex items-center justify-center rounded text-text-secondary hover:bg-bg-hover hover:text-text-primary"
        onClick={onRemove}
      >
        <X size={12} />
      </button>
      <div className="text-xs text-text-secondary uppercase tracking-[0.3px]">{label}</div>
      <button
        className={clsx(
          "px-4 py-2 bg-bg-button text-text-inverse border-none rounded cursor-pointer text-sm text-center transition-colors",
          pressed && "bg-bg-button-hover"
        )}
        onPointerDown={handleDown}
        onPointerUp={handleUp}
        onPointerLeave={handleUp}
      >
        {pressed ? press_value : release_value}
      </button>
    </div>
  );
}

import { useEffect } from 'react';
import { X } from 'lucide-react';
import type { WidgetConfig } from '../../types';
import { sendBindingValue } from './binding';
import { useAppStore } from '../../store/appStore';

interface CheckboxProps {
  widget: Extract<WidgetConfig, { kind: 'Checkbox' }>;
  onRemove: () => void;
}

/// 多选控件 — 切换时发送 checked_value 或 unchecked_value
/// 当前值通过 setInputValue 推送到后端图 (事件驱动, 供下游 widget 读取)
export function Checkbox({ widget, onRemove }: CheckboxProps) {
  const { label, checked_value, unchecked_value, binding, id } = widget.params;
  const checked = useAppStore((s) => {
    const w = s.widgets.find((w) => w.params.id === widget.params.id);
    if (w && w.kind === 'Checkbox') return w.params.default;
    return widget.params.default;
  });
  const updateWidget = useAppStore((s) => s.updateWidget);
  const setInputValue = useAppStore((s) => s.setInputValue);
  const value = checked ? checked_value : unchecked_value;

  const handleToggle = () => {
    const next = !checked;
    updateWidget(widget.params.id, {
      kind: 'Checkbox',
      params: { ...widget.params, default: next },
    });
    sendBindingValue(binding, next ? checked_value : unchecked_value);
  };

  // 同步当前值到后端图 (事件驱动)
  useEffect(() => {
    setInputValue(id, value);
  }, [id, value, setInputValue]);

  return (
    <div className="group bg-bg-sidebar border border-border rounded p-2.5 min-w-[140px] flex flex-col gap-1.5 relative">
      <button
        className="absolute top-1 right-1 opacity-0 transition-opacity duration-150 group-hover:opacity-100 w-6 h-6 flex items-center justify-center rounded text-text-secondary hover:bg-bg-hover hover:text-text-primary"
        onClick={onRemove}
      >
        <X size={12} />
      </button>
      <div className="text-xs text-text-secondary uppercase tracking-[0.3px]">{label}</div>
      <label className="flex items-center gap-1.5 cursor-pointer text-xs">
        <input type="checkbox" checked={checked} onChange={handleToggle} className="accent-accent" />
        <span>
          {checked ? checked_value : unchecked_value}
        </span>
      </label>
    </div>
  );
}

import { useRef, useState, useEffect } from 'react';
import { X } from 'lucide-react';
import type { WidgetConfig } from '../../types';
import { sendBindingValue } from './binding';
import { useAppStore } from '../../store/appStore';

interface KnobProps {
  widget: Extract<WidgetConfig, { kind: 'Knob' }>;
  onRemove: () => void;
}

/// 旋钮控件 — 拖动调节角度, 释放时发送值
/// 当前值通过 setInputValue 推送到后端图 (事件驱动, 供下游 widget 读取)
export function Knob({ widget, onRemove }: KnobProps) {
  const { label, min, max, step, default: def, binding, id } = widget.params;
  const [value, setValue] = useState(def);
  const knobRef = useRef<HTMLDivElement>(null);
  const draggingRef = useRef(false);
  const setInputValue = useAppStore((s) => s.setInputValue);

  // 角度范围: -135° 到 +135° (270° 总行程)
  const angle = ((value - min) / (max - min)) * 270 - 135;

  const handlePointerDown = (e: React.PointerEvent) => {
    draggingRef.current = true;
    (e.target as HTMLElement).setPointerCapture(e.pointerId);
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!draggingRef.current || !knobRef.current) return;
    const rect = knobRef.current.getBoundingClientRect();
    const cx = rect.left + rect.width / 2;
    const cy = rect.top + rect.height / 2;
    const dx = e.clientX - cx;
    const dy = e.clientY - cy;
    // 计算角度 (0 在顶部, 顺时针为正)
    let deg = Math.atan2(dx, -dy) * 180 / Math.PI;
    // 限制在 -135 到 +135
    if (deg > 135) deg = 135;
    if (deg < -135) deg = -135;
    const ratio = (deg + 135) / 270;
    const raw = min + ratio * (max - min);
    const stepped = Math.round(raw / step) * step;
    const clamped = Math.max(min, Math.min(max, stepped));
    setValue(clamped);
  };

  const handlePointerUp = () => {
    if (draggingRef.current) {
      draggingRef.current = false;
      sendBindingValue(binding, value);
    }
  };

  // 鼠标滚轮调整: 向上加 step, 向下减 step
  const handleWheel = (e: React.WheelEvent) => {
    e.preventDefault();
    const dir = e.deltaY < 0 ? 1 : -1;
    // 滚轮加速: 大步长时按 step, 小步长时按 5*step
    const increment = step >= 1 ? step : step * 5;
    const raw = value + dir * increment;
    const stepped = Math.round(raw / step) * step;
    const clamped = Math.max(min, Math.min(max, stepped));
    setValue(clamped);
    sendBindingValue(binding, clamped);
  };

  // 切换控件时重置默认值
  useEffect(() => {
    setValue(def);
  }, [def]);

  // 同步当前值到后端图 (事件驱动, 供下游 widget 读取)
  useEffect(() => {
    setInputValue(id, value);
  }, [id, value, setInputValue]);

  return (
    <div className="group bg-bg-sidebar border border-border rounded p-2.5 min-w-[140px] flex flex-col gap-1.5 relative">
      <button
        className="absolute top-1 right-1 opacity-0 transition-opacity duration-150 group-hover:opacity-100 w-6 h-6 flex items-center justify-center rounded text-text-secondary hover:bg-bg-hover hover:text-text-primary"
        onClick={onRemove}
      >
        <X size={12} />
      </button>
      <div className="text-xs text-text-secondary uppercase tracking-[0.3px]">{label}</div>
      <div className="flex flex-col items-center gap-1">
        <div
          ref={knobRef}
          className="knob-dial"
          onPointerDown={handlePointerDown}
          onPointerMove={handlePointerMove}
          onPointerUp={handlePointerUp}
          onWheel={handleWheel}
        >
          <div
            className="knob-indicator-line"
            style={{ transform: `translateX(-50%) rotate(${angle}deg)` }}
          />
        </div>
        <div className="text-xl font-semibold text-text-bright font-mono text-center">{value.toFixed(2)}</div>
      </div>
    </div>
  );
}

import { useRef, useEffect } from 'react';
import { X } from 'lucide-react';
import type { WidgetConfig } from '../../types';
import { sendBindingValue } from './binding';
import { useAppStore } from '../../store/appStore';

interface SliderProps {
  widget: Extract<WidgetConfig, { kind: 'Slider' }>;
  onRemove: () => void;
}

/// 滑块控件 — 拖动调节, 释放时发送值
/// 当前值通过 setInputValue 推送到后端图 (事件驱动, 供下游 widget 读取)
export function Slider({ widget, onRemove }: SliderProps) {
  const { label, min, max, step, binding } = widget.params;
  const value = useAppStore((s) => {
    const w = s.widgets.find((w) => w.params.id === widget.params.id);
    if (w && w.kind === 'Slider') return w.params.default;
    return widget.params.default;
  });
  const updateWidget = useAppStore((s) => s.updateWidget);
  const setInputValue = useAppStore((s) => s.setInputValue);
  const lastSentRef = useRef(value);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const v = parseFloat(e.target.value);
    updateWidget(widget.params.id, {
      kind: 'Slider',
      params: { ...widget.params, default: v },
    });
  };

  const handleRelease = () => {
    if (value !== lastSentRef.current) {
      sendBindingValue(binding, value);
      lastSentRef.current = value;
    }
  };

  // 鼠标滚轮调整: 向上加 step, 向下减 step
  const handleWheel = (e: React.WheelEvent) => {
    e.preventDefault();
    const dir = e.deltaY < 0 ? 1 : -1;
    const increment = step >= 1 ? step : step * 5;
    const raw = value + dir * increment;
    const stepped = Math.round(raw / step) * step;
    const clamped = Math.max(min, Math.min(max, stepped));
    updateWidget(widget.params.id, {
      kind: 'Slider',
      params: { ...widget.params, default: clamped },
    });
    sendBindingValue(binding, clamped);
    lastSentRef.current = clamped;
  };

  // 同步当前值到后端图 (事件驱动, 供下游 widget 读取)
  useEffect(() => {
    setInputValue(widget.params.id, value);
  }, [widget.params.id, value, setInputValue]);

  return (
    <div className="group bg-bg-sidebar border border-border rounded p-2.5 min-w-[140px] flex flex-col gap-1.5 relative">
      <button
        className="absolute top-1 right-1 opacity-0 transition-opacity duration-150 group-hover:opacity-100 w-6 h-6 flex items-center justify-center rounded text-text-secondary hover:bg-bg-hover hover:text-text-primary"
        onClick={onRemove}
      >
        <X size={12} />
      </button>
      <div className="text-xs text-text-secondary uppercase tracking-[0.3px]">{label}</div>
      <div className="flex flex-col gap-1 w-full">
        <input
          type="range"
          className="slider-input"
          min={min}
          max={max}
          step={step}
          value={value}
          onChange={handleChange}
          onPointerUp={handleRelease}
          onKeyUp={handleRelease}
          onWheel={handleWheel}
        />
        <div className="text-xl font-semibold text-text-bright font-mono text-center">{value.toFixed(2)}</div>
      </div>
    </div>
  );
}

import { useEffect } from 'react';
import { X } from 'lucide-react';
import type { WidgetConfig } from '../../types';
import { sendBindingValue } from './binding';
import { useAppStore } from '../../store/appStore';
import { t } from '../../i18n';

interface RadioProps {
  widget: Extract<WidgetConfig, { kind: 'Radio' }>;
  onRemove: () => void;
}

/// 单选控件 — 选择选项后发送对应值
/// 当前值通过 setInputValue 推送到后端图 (事件驱动, 供下游 widget 读取)
export function Radio({ widget, onRemove }: RadioProps) {
  const lang = useAppStore((s) => s.lang);
  const { label, options, binding, id } = widget.params;
  const current = useAppStore((s) => {
    const w = s.widgets.find((w) => w.params.id === widget.params.id);
    if (w && w.kind === 'Radio') return w.params.default;
    return widget.params.default;
  });
  const updateWidget = useAppStore((s) => s.updateWidget);
  const setInputValue = useAppStore((s) => s.setInputValue);
  const value = options[current]?.[1] ?? 0;

  const handleChange = (val: number) => {
    updateWidget(widget.params.id, {
      kind: 'Radio',
      params: { ...widget.params, default: val },
    });
    sendBindingValue(binding, val);
  };

  // 同步当前值到后端图 (事件驱动)
  useEffect(() => {
    setInputValue(id, value);
  }, [id, value, setInputValue]);

  return (
    <div className="group bg-bg-sidebar border border-border rounded p-2.5 min-w-[140px] flex flex-col gap-1.5 relative">
      <button
        className="absolute top-1 right-1 opacity-0 transition-opacity duration-150 group-hover:opacity-100 w-6 h-6 flex items-center justify-center rounded text-text-secondary hover:bg-bg-hover hover:text-text-primary"
        onClick={onRemove}
      >
        <X size={12} />
      </button>
      <div className="text-xs text-text-secondary uppercase tracking-[0.3px]">{label}</div>
      <div className="flex flex-col gap-1">
        {options.map(([text, val]) => (
          <label key={val} className="flex items-center gap-1.5 cursor-pointer text-xs">
            <input
              type="radio"
              name={widget.params.id}
              checked={current === val}
              onChange={() => handleChange(val)}
              className="accent-accent"
            />
            <span>{text}</span>
          </label>
        ))}
      </div>
      <div className="text-xs text-text-secondary">
        {t(lang, 'channel')}: {current}
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { X } from 'lucide-react';
import type { WidgetConfig } from '../../types';
import { waveformWindow } from '../../lib/dataBuffer';

interface LabelProps {
  widget: Extract<WidgetConfig, { kind: 'Label' }>;
  onRemove: () => void;
}

/// 标签控件 — 显示通道实时值或固定文本
export function Label({ widget, onRemove }: LabelProps) {
  const { text, channel } = widget.params;
  const [display, setDisplay] = useState(text);

  useEffect(() => {
    // 无通道绑定: 显示静态文本
    if (channel === null) {
      setDisplay(text);
      return;
    }

    // 绑定通道: 轮询后端波形窗口缓存
    setDisplay(text);
    const interval = setInterval(() => {
      const win = waveformWindow.get();
      const ch = win.channels[channel];
      if (ch && ch.length > 0) {
        const last = ch[ch.length - 1];
        setDisplay(`${text}: ${last.toFixed(3)}`);
      }
    }, 100);

    return () => clearInterval(interval);
  }, [text, channel]);

  return (
    <div className="group bg-bg-sidebar border border-border rounded p-2.5 min-w-[140px] flex flex-col gap-1.5 relative">
      <button
        className="absolute top-1 right-1 opacity-0 transition-opacity duration-150 group-hover:opacity-100 w-6 h-6 flex items-center justify-center rounded text-text-secondary hover:bg-bg-hover hover:text-text-primary"
        onClick={onRemove}
      >
        <X size={12} />
      </button>
      <div className="text-xs text-text-secondary uppercase tracking-[0.3px]">{channel === null ? 'Label' : `CH${channel}`}</div>
      <div className="text-xl font-semibold text-text-bright font-mono text-center">{display}</div>
    </div>
  );
}

