        style={{ aspectRatio: `${width} / ${height}` }}
      >
        {hasImage ? (
          <canvas width={width} height={height} />
        ) : (
          <div className="flex flex-col gap-1 items-center">
            <ImageIcon size={24} className="opacity-40" />
            <span>
              {width}×{height} {format}
            </span>
          </div>
