import { useCallback, useRef, useEffect } from 'react';

interface StepKnobProps {
  /// 当前值
  value: number;
  /// 离散档位序列 (1-2-5 序列等)
  steps: number[];
  /// 切换档位回调
  onChange: (newValue: number) => void;
  /// 双击/中心点击时的默认值 (用于重置)
  defaultValue?: number;
  /// 值显示格式化函数
  formatValue: (v: number) => string;
  /// 标签 (显示在旋钮下方)
  label?: string;
  /// 像素直径, 默认 56
  size?: number;
  /// 是否禁用
  disabled?: boolean;
}

/// 离散档位旋钮组件
/// - 拖动垂直方向改变档位 (上 = 加大, 下 = 减小)
/// - 滚轮也可改变档位 (使用原生非被动监听器, 避免页面同时滚动)
/// - 中心点击重置为 defaultValue
/// 旋钮指针角度: 最小档位 = -135°, 最大档位 = +135° (共 270°)
export function StepKnob({
  value,
  steps,
  onChange,
  defaultValue,
  formatValue,
  label,
  size = 56,
  disabled = false,
}: StepKnobProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const dragRef = useRef<{ startY: number; startIdx: number } | null>(null);

  const currentIndex = steps.indexOf(value);
  const safeIdx = currentIndex >= 0 ? currentIndex : 0;
  const totalSteps = steps.length;
  // -135° 到 +135°, 共 270°
  const angle = totalSteps > 1
    ? (safeIdx / (totalSteps - 1)) * 270 - 135
    : 0;

  const stepTo = useCallback(
    (newIdx: number) => {
      const clamped = Math.max(0, Math.min(totalSteps - 1, newIdx));
      if (clamped !== currentIndex) {
        onChange(steps[clamped]);
      }
    },
    [onChange, steps, totalSteps, currentIndex]
  );

  // 用 ref 保存最新的 stepTo / disabled / safeIdx, 让原生 wheel 监听器能访问最新值
  const stepToRef = useRef(stepTo);
  useEffect(() => { stepToRef.current = stepTo; }, [stepTo]);
  const disabledRef = useRef(disabled);
  useEffect(() => { disabledRef.current = disabled; }, [disabled]);
  const safeIdxRef = useRef(safeIdx);
  useEffect(() => { safeIdxRef.current = safeIdx; }, [safeIdx]);

  // 原生非被动 wheel 监听器 — React onWheel 默认 passive, preventDefault 无效会导致页面滚动
  useEffect(() => {
    const el = containerRef.current;
    if (!el) return;
    const onWheel = (e: WheelEvent) => {
      if (disabledRef.current) return;
      e.preventDefault();
      e.stopPropagation();
      const dir = e.deltaY > 0 ? -1 : 1;
      stepToRef.current(safeIdxRef.current + dir);
    };
    el.addEventListener('wheel', onWheel, { passive: false });
    return () => el.removeEventListener('wheel', onWheel);
  }, []);

  const handlePointerDown = useCallback(
    (e: React.PointerEvent) => {
      if (disabled) return;
      e.preventDefault();
      e.stopPropagation();
      (e.currentTarget as HTMLElement).setPointerCapture(e.pointerId);
      dragRef.current = { startY: e.clientY, startIdx: safeIdx };
    },
    [disabled, safeIdx]
  );

  const handlePointerMove = useCallback(
    (e: React.PointerEvent) => {
      if (!dragRef.current || disabled) return;
      const dy = dragRef.current.startY - e.clientY;
      // 每 12px 一档
      const delta = Math.round(dy / 12);
      stepTo(dragRef.current.startIdx + delta);
    },
    [disabled, stepTo]
  );

  const handlePointerUp = useCallback(
    (e: React.PointerEvent) => {
      if (dragRef.current) {
        (e.currentTarget as HTMLElement).releasePointerCapture(e.pointerId);
        dragRef.current = null;
      }
    },
    []
  );

  const handleDoubleClick = useCallback(() => {
    if (disabled) return;
    if (defaultValue !== undefined && defaultValue !== value) {
      onChange(defaultValue);
    }
  }, [disabled, defaultValue, value, onChange]);

  return (
    <div
      ref={containerRef}
      className={`flex flex-col items-center gap-0.5 select-none ${disabled ? 'opacity-40 pointer-events-none' : ''}`}
      style={{ width: size }}
    >
      <div
        className="step-knob-dial"
        style={{
          width: size,
          height: size,
          transform: `rotate(${angle}deg)`,
        }}
        onPointerDown={handlePointerDown}
        onPointerMove={handlePointerMove}
        onPointerUp={handlePointerUp}
        onDoubleClick={handleDoubleClick}
      >
        <div className="step-knob-pointer" />
        <div className="step-knob-rim" />
      </div>
      <div className="font-mono text-[10px] text-text-bright max-w-full overflow-hidden text-ellipsis whitespace-nowrap" title={formatValue(value)}>
        {formatValue(value)}
      </div>
      {label && <div className="text-[9px] text-text-secondary uppercase tracking-[0.5px]">{label}</div>}
    </div>
  );
}

import { type ReactNode } from 'react';
import { X, Settings2 } from 'lucide-react';
import clsx from 'clsx';

export interface WidgetCardProps {
  children: ReactNode;
  /** Header label at top (uppercase, text-secondary) */
  label?: string;
  /** Badge text in a colored pill (e.g. filter preset, math op symbol) */
  badge?: string;
  /** Tailwind color name for the badge — controls bg/text/border shades */
  badgeColor?: 'blue' | 'green' | 'orange' | 'purple' | 'red' | 'accent' | 'yellow' | 'indigo';
  /** Show remove (×) button on hover */
  onRemove?: () => void;
  /** Show edit (⚙) button on hover */
  onEdit?: () => void;
  /** Remove the min-w-[140px] constraint */
  noMinWidth?: boolean;
  /** Extra classes applied to the card element */
  className?: string;
}

const BADGE_CLASSES: Record<string, string> = {
  blue: 'bg-blue/20 text-blue border-blue/40',
  green: 'bg-green/20 text-green border-green/40',
  orange: 'bg-orange/20 text-orange border-orange/40',
  purple: 'bg-purple/20 text-purple border-purple/40',
  red: 'bg-red/20 text-red border-red/40',
  accent: 'bg-accent/20 text-accent border-accent/40',
  yellow: 'bg-yellow/20 text-yellow border-yellow/40',
  indigo: 'bg-indigo/20 text-indigo border-indigo/40',
};

/// VSCode-style widget card — the shared container for all control & display widgets
///
/// Provides:
///   1. Standard card container (dark sidebar background + border + rounded)
///   2. Hover-reveal remove (×) and edit (⚙) buttons at top-right
///   3. Optional header label (uppercase, text-secondary)
///   4. Optional colored badge pill
///   5. Children slot for widget-specific content
export function WidgetCard({
  children,
  label,
  badge,
  badgeColor = 'accent',
  onRemove,
  onEdit,
  noMinWidth = false,
  className,
}: WidgetCardProps) {
  return (
    <div
      className={clsx(
        'group bg-bg-sidebar border border-border rounded p-2.5 flex flex-col gap-1.5 relative',
        !noMinWidth && 'min-w-[140px]',
        className,
      )}
    >
      {/* Remove button (×) — top-right corner */}
      {onRemove && (
        <button
          type="button"
          className="absolute top-1 right-1 opacity-0 transition-opacity duration-150 group-hover:opacity-100 w-6 h-6 flex items-center justify-center rounded text-text-secondary hover:bg-bg-hover hover:text-text-primary cursor-pointer z-10"
          onClick={onRemove}
        >
          <X size={12} />
        </button>
      )}

      {/* Edit button (⚙) — sits left of remove when both exist */}
      {onEdit && (
        <button
          type="button"
          className={clsx(
            'absolute top-1 opacity-0 transition-opacity duration-150 group-hover:opacity-100 w-6 h-6 flex items-center justify-center rounded text-text-secondary hover:bg-bg-hover hover:text-text-primary cursor-pointer z-10',
            onRemove ? 'right-7' : 'right-1',
          )}
          onClick={onEdit}
          title="Edit"
        >
          <Settings2 size={11} />
        </button>
      )}

      {/* Header row: badge pill + label text */}
      {(badge || label) && (
        <div className="flex items-center gap-1.5">
          {badge && (
            <span
              className={clsx(
                'px-1.5 py-0.5 rounded-sm text-[10px] font-semibold w-fit border',
                BADGE_CLASSES[badgeColor] ?? BADGE_CLASSES.accent,
              )}
            >
              {badge}
            </span>
          )}
          {label && (
            <div className="text-xs text-text-secondary uppercase tracking-[0.3px]">
              {label}
            </div>
          )}
        </div>
      )}

      {children}
    </div>
  );
}

