import { useEffect, useRef } from 'react';
import { WidgetCard } from '../ui/WidgetCard';
import type { WidgetConfig } from '../../types';
import { useGraphInput } from '../../lib/useGraphInput';

interface GaugeProps {
  widget: Extract<WidgetConfig, { kind: 'Gauge' }>;
  onRemove: () => void;
  onEdit?: () => void;
}

/// 仪表盘控件 — 半圆指针 + 弧形进度, 显示单通道实时值
/// 数据源: edge 连线 (后端图输出) 优先, 否则回退到 channel 参数
export function Gauge({ widget, onEdit }: GaugeProps) {
  const { min, max, unit, channel } = widget.params;
  const value = useGraphInput(widget.params.id, 'value', channel, min);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // 绘制半圆仪表盘
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    const cssVar = (name: string) => getComputedStyle(document.documentElement).getPropertyValue(name).trim();
    if (!ctx) return;

    const dpr = window.devicePixelRatio || 1;
    const rect = canvas.getBoundingClientRect();
    canvas.width = rect.width * dpr;
    canvas.height = rect.height * dpr;
    ctx.scale(dpr, dpr);

    const w = rect.width;
    const h = rect.height;
    const cx = w / 2;
    const cy = h * 0.85;
    const radius = Math.min(w / 2 - 8, h * 0.75);

    ctx.clearRect(0, 0, w, h);

    // 半圆范围: 180° (左) ~ 0° (右)
    const startAngle = Math.PI;          // 180°
    const endAngle = 0;                 // 0°
    const totalAngle = startAngle - endAngle;

    // 背景弧 (灰色)
    ctx.strokeStyle = cssVar('--color-border') || '#3c3c3c';
    ctx.lineWidth = 8;
    ctx.lineCap = 'round';
    ctx.beginPath();
    ctx.arc(cx, cy, radius, endAngle, startAngle);
    ctx.stroke();

    // 进度弧 (蓝色)
    const ratio = Math.max(0, Math.min(1, (value - min) / (max - min || 1)));
    const valueAngle = startAngle - ratio * totalAngle;
    ctx.strokeStyle = cssVar('--color-blue') || '#75beff';
    ctx.beginPath();
    ctx.arc(cx, cy, radius, valueAngle, startAngle);
    ctx.stroke();

    // 刻度 (5 段)
    ctx.strokeStyle = cssVar('--color-text-secondary') || '#858585';
    ctx.lineWidth = 1;
    ctx.fillStyle = cssVar('--color-text-secondary') || '#858585';
    ctx.font = '9px sans-serif';
    ctx.textAlign = 'center';
    for (let i = 0; i <= 4; i++) {
      const r = i / 4;
      const a = startAngle - r * totalAngle;
      const x1 = cx + Math.cos(a) * (radius - 12);
      const y1 = cy + Math.sin(a) * (radius - 12);
      const x2 = cx + Math.cos(a) * (radius - 4);
      const y2 = cy + Math.sin(a) * (radius - 4);
      ctx.beginPath();
      ctx.moveTo(x1, y1);
      ctx.lineTo(x2, y2);
      ctx.stroke();

      // 刻度标签
      const tickVal = min + r * (max - min);
      const lx = cx + Math.cos(a) * (radius - 22);
      const ly = cy + Math.sin(a) * (radius - 22) + 3;
      const txt = Math.abs(tickVal) >= 100 ? tickVal.toFixed(0) : tickVal.toFixed(1);
      ctx.fillText(txt, lx, ly);
    }

    // 指针
    ctx.strokeStyle = cssVar('--color-red') || '#f48771';
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(cx, cy);
    ctx.lineTo(
      cx + Math.cos(valueAngle) * (radius - 8),
      cy + Math.sin(valueAngle) * (radius - 8)
    );
    ctx.stroke();

    // 中心圆
    ctx.fillStyle = cssVar('--color-text-primary') || '#cccccc';
    ctx.beginPath();
    ctx.arc(cx, cy, 4, 0, Math.PI * 2);
    ctx.fill();
  }, [value, min, max]);

  return (
    <WidgetCard onEdit={onEdit} noMinWidth>
      <div className="flex flex-col items-center gap-1">
        <canvas ref={canvasRef} style={{ width: '100%', height: 90 }} />
        <div className="font-mono text-lg font-semibold text-text-bright text-center">
          {value.toFixed(2)}
          {unit && <span className="ml-1 text-[10px] text-text-secondary font-normal">{unit}</span>}
        </div>
      </div>
    </WidgetCard>
  );
}

import { WidgetCard } from '../ui/WidgetCard';
import type { WidgetConfig } from '../../types';
import { useGraphInput } from '../../lib/useGraphInput';

interface LEDProps {
  widget: Extract<WidgetConfig, { kind: 'LED' }>;
  onRemove: () => void;
  onEdit?: () => void;
}

/// LED 指示灯 — 输入值 >= threshold 显示 ON 颜色, 否则 OFF
/// 数据源: edge 连线 (后端图输出) 优先, 否则回退到 channel 参数
export function LED({ widget, onEdit }: LEDProps) {
  const { threshold, on_color, off_color, channel } = widget.params;
  const value = useGraphInput(widget.params.id, 'value', channel, 0);

  const isOn = value >= threshold;
  const color = isOn ? on_color : off_color;

  return (
    <WidgetCard onEdit={onEdit}>
      <div className="flex flex-col items-center gap-1 py-1.5">
        <div
          className={`w-7 h-7 rounded-full border-2 border-[#1e1e1e] transition-[background,box-shadow] duration-100 ${isOn ? 'animate-led-pulse' : ''}`}
          style={{
            background: color,
            boxShadow: isOn ? `0 0 14px ${color}, 0 0 4px ${color}` : 'none',
          }}
        />
        <div className="text-[10px] font-bold text-text-secondary tracking-[0.5px]">{isOn ? 'ON' : 'OFF'}</div>
        <div className="font-mono text-[10px] text-text-secondary">{value.toFixed(3)}</div>
      </div>
    </WidgetCard>
  );
}

import { WidgetCard } from '../ui/WidgetCard';
import type { WidgetConfig } from '../../types';
import { useGraphInput } from '../../lib/useGraphInput';

interface NumberDisplayProps {
  widget: Extract<WidgetConfig, { kind: 'NumberDisplay' }>;
  onRemove: () => void;
  onEdit?: () => void;
}

/// 大数字显示 — 大字号展示单通道数值, 含单位与小数位
/// 数据源: edge 连线 (后端图输出) 优先, 否则回退到 channel 参数
export function NumberDisplay({ widget, onEdit }: NumberDisplayProps) {
  const { unit, precision, channel } = widget.params;
  const value = useGraphInput(widget.params.id, 'value', channel, 0);

  // 自适应字号: 值越长字号越小
  const text = value.toFixed(precision);
  const fontSize = text.length > 10 ? 18 : text.length > 7 ? 24 : 32;

  return (
    <WidgetCard onEdit={onEdit}>
      <div className="flex items-baseline justify-center gap-1 px-1 py-3 min-h-[56px]">
        <span className="font-mono font-bold text-text-bright tracking-[-0.5px] leading-none" style={{ fontSize }}>
          {text}
        </span>
        {unit && <span className="text-sm text-text-secondary font-normal">{unit}</span>}
      </div>
      {channel === null && (
        <div className="text-[10px] text-text-secondary text-center opacity-60">未绑定通道</div>
      )}
    </WidgetCard>
  );
}

import { useMemo } from 'react';
import { Plus } from 'lucide-react';
import { WidgetCard } from '../ui/WidgetCard';
import type { WidgetConfig, MathOp } from '../../types';
import { UNARY_MATH_OPS } from '../../types';
import { useAppStore } from '../../store/appStore';
import { useGraphInputs } from '../../lib/useGraphInput';

interface MathWidgetProps {
  widget: Extract<WidgetConfig, { kind: 'Math' }>;
  onRemove: () => void;
  onEdit?: () => void;
}

/// 运算符显示符号
const OP_SYMBOLS: Record<MathOp, string> = {
  add: '+',
  sub: '−',
  mul: '×',
  div: '÷',
  avg: 'avg',
  min: 'min',
  max: 'max',
  abs: '|x|',
  neg: '−x',
  square: 'x²',
  sqrt: '√x',
  sin: 'sin',
  cos: 'cos',
  tan: 'tan',
  log: 'ln',
};

/// 算术控件 — 显示后端图评估的运算结果
///
/// 数据流 (后端评估, 60 FPS 推送):
///   1. 后端 CompiledGraph 按拓扑序评估: 收集本节点的输入 → 调用 MathOp::evaluate → 写入输出端口 "result"
///   2. 后端 graph_output_ticker 每 16ms 将所有节点输出快照推送至前端
///   3. 本组件直接读 graphOutputs[id].result 显示结果
///   4. 输入端口值 (用于展开显示) 通过 useGraphInputs 读上游输出
export function MathWidget({ widget, onEdit }: MathWidgetProps) {
  const { op, unit, precision, inputCount, id } = widget.params;
  // 只订阅本 widget 的结果, 避免 graphOutputs 全局更新时所有 MathWidget 重渲染
  const result = useAppStore((s) => s.graphOutputs[id]?.result ?? 0);

  // 输入端口展示 (单目运算只显示 1 个端口)
  const inputPorts = useMemo(
    () =>
      Array.from({ length: inputCount }, (_, i) => ({
        id: `in${i}`,
        label: UNARY_MATH_OPS.includes(op) && i > 0 ? '' : `in${i}`,
      })),
    [inputCount, op]
  );

  // 读取各输入端口的值 (用于显示, 后端已用这些值算出 result)
  const inputs = useGraphInputs(id, inputPorts.map((p) => p.id), 0);

  const isConnected = Object.keys(inputs).length > 0 &&
    Object.values(inputs).some((v) => v !== 0);
  const symbol = OP_SYMBOLS[op];

  return (
    <WidgetCard badge={symbol} badgeColor="yellow" onEdit={onEdit}>
      <div className="flex flex-col gap-1.5">
        <div className="flex items-baseline gap-1 justify-center py-1.5">
          <span
            className="font-semibold text-text-primary font-mono tracking-[-0.5px]"
            style={{ fontSize: result.toFixed(precision).length > 8 ? 16 : 22 }}
          >
            {result.toFixed(precision)}
          </span>
          {unit && <span className="text-xs text-text-secondary">{unit}</span>}
        </div>
        {!isConnected && (
          <div className="flex items-center gap-1 justify-center p-1 text-[10px] text-text-secondary opacity-70">
            <Plus size={10} />
            <span>连接输入</span>
          </div>
        )}
        {isConnected && (
          <div className="flex flex-col gap-0.5 border-t border-dashed border-border pt-1 mt-0.5">
            {inputPorts.map((p) => (
              <div key={p.id} className="flex justify-between items-center text-[10px] px-0.5 py-px">
                <span className="text-text-secondary font-mono">{p.label}</span>
                <span className="text-text-primary font-mono">
                  {inputs[p.id] !== undefined ? inputs[p.id].toFixed(precision) : '—'}
                </span>
              </div>
            ))}
          </div>
        )}
      </div>
    </WidgetCard>
  );
}

